init_performance2();
var ZEPTO_API = "https://api.zeptomail.in/v1.1/email";
var FROM_NAME = "Cephlow Certificates";
async function sendEmail(env2, {
  to,
  subject,
  body,
  pdfBuffer,
  pdfFilename
}) {
  const fromEmail = env2.ZEPTOMAIL_FROM_EMAIL || "certificate@cephlow.in";
  const payload = {
    from: { address: fromEmail, name: FROM_NAME },
    to: [{ email_address: { address: to } }],
    subject,
    textbody: body
  };
  if (pdfBuffer) {
    let base64Content = "";
    if (typeof pdfBuffer === "string") {
      base64Content = pdfBuffer;
    } else {
      const bytes = new Uint8Array(pdfBuffer);
      let binary = "";
      const len = bytes.byteLength;
      for (let i2 = 0; i2 < len; i2++) {
        binary += String.fromCharCode(bytes[i2]);
      }
      base64Content = btoa(binary);
    }
    payload.attachments = [
      {
        content: base64Content,
        mime_type: "application/pdf",
        name: pdfFilename || "certificate.pdf"
      }
    ];
  }
  const res = await fetch(ZEPTO_API, {
    method: "POST",
    headers: {
      "Accept": "application/json",
      "Content-Type": "application/json",
      "Authorization": env2.ZEPTOMAIL_TOKEN
    },
    body: JSON.stringify(payload)
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(`ZeptoMail error ${res.status}: ${JSON.stringify(err)}`);
  }
}
__name(sendEmail, "sendEmail");

