router17.patch("/marketplace/listings/:id", async (c2) => {
  const user = c2.get("user");
  const { id } = c2.req.param();
  try {
    const { name, description, price, isActive } = await c2.req.json().catch(() => ({}));
    const existing = await c2.env.DB.prepare(`
      SELECT id, published_by, frame_id FROM frame_listings WHERE id = ?
    `).bind(id).first();
    if (!existing) return c2.json({ error: "Listing not found" }, 404);
    if (existing.published_by !== user.uid) return c2.json({ error: "Access denied" }, 403);
    if (price !== void 0) {
      const priceNum = Number(price);
      if (isNaN(priceNum) || priceNum !== 0 && (priceNum < 20 || priceNum > 100)) {
        return c2.json({ error: "price must be 0 or between 20 and 100" }, 400);
      }
    }
    if (isActive === true) {
      const other = await c2.env.DB.prepare(`
        SELECT id FROM frame_listings WHERE frame_id = ? AND is_active = 1 AND id != ?
      `).bind(existing.frame_id, id).first();
      if (other) {
        return c2.json({ error: "Another active listing already exists for this frame" }, 409);
      }
    }
    const fields = ["updated_at = datetime('now')"];
    const params = [];
    if (name !== void 0) {
      fields.push("name = ?");
      params.push(name.trim());
    }
    if (description !== void 0) {
      fields.push("description = ?");
      params.push(description.trim());
    }
    if (price !== void 0) {
      fields.push("price = ?");
      params.push(Number(price));
    }
    if (isActive !== void 0) {
      fields.push("is_active = ?");
      params.push(isActive ? 1 : 0);
    }
    params.push(id);
    await c2.env.DB.prepare(`
      UPDATE frame_listings
      SET ${fields.join(", ")}
      WHERE id = ?
    `).bind(...params).run();
    const listing = await c2.env.DB.prepare(`
      SELECT * FROM frame_listings WHERE id = ?
    `).bind(id).first();
    return c2.json(listing);
  } catch (err) {
    return c2.json({ error: err.message }, 500);
  }
});
