router17.post("/marketplace/listings/:id/purchase", async (c2) => {
  const user = c2.get("user");
  const workspace = c2.get("workspace");
  const { id } = c2.req.param();
  try {
    const { batchId } = await c2.req.json().catch(() => ({}));
    const listing = await c2.env.DB.prepare(`
      SELECT * FROM frame_listings WHERE id = ? AND is_active = 1
    `).bind(id).first();
    if (!listing) return c2.json({ error: "Listing not found" }, 404);
    const already = await c2.env.DB.prepare(`
      SELECT id FROM frame_purchases WHERE listing_id = ? AND workspace_id = ?
    `).bind(id, workspace.id).first();
    if (already) {
      return c2.json({
        success: true,
        alreadyOwned: true,
        frameTier: `marketplace:${id}`
      });
    }
    const price = listing.price;
    const ws = await c2.env.DB.prepare(`
      SELECT current_balance FROM workspaces WHERE id = ?
    `).bind(workspace.id).first();
    if (!ws) return c2.json({ error: "Workspace not found" }, 404);
    if (price > 0 && ws.current_balance < price) {
      return c2.json({
        error: "Insufficient workspace balance",
        required: price,
        available: ws.current_balance
      }, 402);
    }
    const newWsBalance = ws.current_balance - price;
    const stmts = [];
    if (price > 0) {
      stmts.push(c2.env.DB.prepare(`UPDATE workspaces SET current_balance = ? WHERE id = ?`).bind(newWsBalance, workspace.id));
      stmts.push(c2.env.DB.prepare(`
        INSERT INTO ledgers (id, workspace_id, user_id, type, amount, balance_after, description, metadata)
        VALUES (?, ?, ?, 'deduction', ?, ?, ?, ?)
      `).bind(
        crypto.randomUUID(),
        workspace.id,
        user.uid,
        -price,
        newWsBalance,
        `Marketplace frame: ${listing.name}`,
        JSON.stringify({ listingId: id, frameTier: `marketplace:${id}`, batchId: batchId || null })
      ));
      const creatorProfile = await c2.env.DB.prepare(`
        SELECT creator_credits FROM user_profiles WHERE id = ?
      `).bind(listing.published_by).first();
      const newCreatorCredits = (creatorProfile?.creator_credits || 0) + price;
      stmts.push(c2.env.DB.prepare(`UPDATE user_profiles SET creator_credits = ? WHERE id = ?`).bind(newCreatorCredits, listing.published_by));
    }
    stmts.push(c2.env.DB.prepare(`
      INSERT INTO frame_purchases (listing_id, workspace_id, purchased_by, batch_id, amount_paid, creator_uid)
      VALUES (?, ?, ?, ?, ?, ?)
    `).bind(id, workspace.id, user.uid, batchId || null, price, listing.published_by));
    stmts.push(c2.env.DB.prepare(`
      UPDATE frame_listings 
      SET purchase_count = purchase_count + 1, updated_at = datetime('now')
      WHERE id = ?
    `).bind(id));
    await c2.env.DB.batch(stmts);
    return c2.json({
      success: true,
      alreadyOwned: false,
      frameTier: `marketplace:${id}`
    });
  } catch (err) {
    return c2.json({ error: err.message }, 500);
  }
});
router17.post("/marketplace/listings/:id/like", async (c2) => {
  const user = c2.get("user");
  const { id } = c2.req.param();
  try {
    const listing = await c2.env.DB.prepare(`
      SELECT like_count FROM frame_listings WHERE id = ? AND is_active = 1
    `).bind(id).first();
    if (!listing) return c2.json({ error: "Listing not found" }, 404);
    const existingLike = await c2.env.DB.prepare(`
      SELECT 1 FROM frame_likes WHERE listing_id = ? AND user_id = ?
    `).bind(id, user.uid).first();
    let liked = false;
    let newLikeCount = listing.like_count ?? 0;
    if (existingLike) {
      newLikeCount = Math.max(0, newLikeCount - 1);
      await c2.env.DB.batch([
        c2.env.DB.prepare(`DELETE FROM frame_likes WHERE listing_id = ? AND user_id = ?`).bind(id, user.uid),
        c2.env.DB.prepare(`UPDATE frame_listings SET like_count = ?, updated_at = datetime('now') WHERE id = ?`).bind(newLikeCount, id)
      ]);
      liked = false;
    } else {
      newLikeCount += 1;
      await c2.env.DB.batch([
        c2.env.DB.prepare(`INSERT INTO frame_likes (listing_id, user_id) VALUES (?, ?)`).bind(id, user.uid),
        c2.env.DB.prepare(`UPDATE frame_listings SET like_count = ?, updated_at = datetime('now') WHERE id = ?`).bind(newLikeCount, id)
      ]);
      liked = true;
    }
    return c2.json({ liked, likeCount: newLikeCount });
  } catch (err) {
    return c2.json({ error: err.message }, 500);
  }
});
